import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  const [selectedFile, setSelectedFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [predictions, setPredictions] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [dragOver, setDragOver] = useState(false);
  const [apiUrl] = useState('http://localhost:8000');
  const [navScrolled, setNavScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const fileInputRef = useRef(null);
  const uploadSectionRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => setNavScrolled(window.scrollY > 40);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('visible');
          }
        });
      },
      { threshold: 0.15 }
    );
    document.querySelectorAll('.reveal').forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, []);

  const handleFileSelect = (file) => {
    if (!file) return;
    if (!file.type.startsWith('image/')) {
      setError('Please select a valid image file.');
      return;
    }
    if (file.size > 50 * 1024 * 1024) {
      setError('File size must be less than 50MB.');
      return;
    }
    setSelectedFile(file);
    setError(null);
    setPredictions(null);
    const reader = new FileReader();
    reader.onloadend = () => setPreview(reader.result);
    reader.readAsDataURL(file);
  };

  const handleInputChange = (e) => handleFileSelect(e.target.files[0]);

  const handleDrop = (e) => {
    e.preventDefault();
    setDragOver(false);
    handleFileSelect(e.dataTransfer.files[0]);
  };

  const handlePredict = async () => {
    if (!selectedFile) { setError('Please select an image first.'); return; }
    setLoading(true);
    setError(null);
    setPredictions(null);
    try {
      const formData = new FormData();
      formData.append('file', selectedFile);
      const response = await axios.post(`${apiUrl}/predict`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' },
        timeout: 30000,
      });
      setPredictions(response.data);
    } catch (err) {
      if (err.response?.status === 503) setError('Model not loaded. Please train the model first.');
      else if (err.response?.data?.detail) setError(err.response.data.detail);
      else if (err.code === 'ECONNREFUSED') setError('Cannot connect to backend. Is the server running on http://localhost:8000?');
      else setError(err.message || 'Error making prediction');
    } finally {
      setLoading(false);
    }
  };

  const handleClear = () => {
    setSelectedFile(null);
    setPreview(null);
    setPredictions(null);
    setError(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const scrollToUpload = () => {
    uploadSectionRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const getConfidenceColor = (conf) => {
    if (conf >= 80) return '#22c55e';
    if (conf >= 50) return '#f59e0b';
    return '#ef4444';
  };

  return (
    <div className="App">

      {/* ── NAV ── */}
      <nav className={`navbar ${navScrolled ? 'scrolled' : ''}`}>
        <div className="nav-inner">
          <a href="#hero" className="nav-logo">
            <span className="logo-icon">🐄</span>
            <span className="logo-text">BreedAI</span>
          </a>
          <div className={`nav-links ${mobileMenuOpen ? 'open' : ''}`}>
            <a href="#features" onClick={() => setMobileMenuOpen(false)}>Features</a>
            <a href="#how-it-works" onClick={() => setMobileMenuOpen(false)}>How It Works</a>
            <a href="#about" onClick={() => setMobileMenuOpen(false)}>About</a>
            <a href="#contact" onClick={() => setMobileMenuOpen(false)}>Contact</a>
            <button className="nav-cta" onClick={() => { setMobileMenuOpen(false); scrollToUpload(); }}>Try Now</button>
          </div>
          <button className="hamburger" onClick={() => setMobileMenuOpen(!mobileMenuOpen)} aria-label="Toggle menu">
            <span></span><span></span><span></span>
          </button>
        </div>
      </nav>

      {/* ── HERO ── */}
      <section id="hero" className="hero">
        <div className="hero-bg">
          <div className="orb orb-1"></div>
          <div className="orb orb-2"></div>
          <div className="orb orb-3"></div>
          <div className="grid-overlay"></div>
        </div>
        <div className="hero-content">
          <div className="hero-badge">
            <span className="badge-dot"></span>
            Powered by ResNet-50 Deep Learning
          </div>
          <h1 className="hero-title">
            Identify Cattle &<br />
            <span className="gradient-text">Buffalo Breeds</span><br />
            Instantly with AI
          </h1>
          <p className="hero-subtitle">
            Upload a photo — our deep learning model analyzes it in seconds and returns
            the breed, confidence score, and detailed origin information.
          </p>
          <div className="hero-actions">
            <button className="btn-hero-primary" onClick={scrollToUpload}>
              <span>Start Identifying</span>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M5 12h14M12 5l7 7-7 7"/></svg>
            </button>
            <a href="#how-it-works" className="btn-hero-ghost">See How It Works</a>
          </div>
          <div className="hero-stats">
            <div className="stat"><strong>50+</strong><span>Breeds</span></div>
            <div className="stat-divider"></div>
            <div className="stat"><strong>ResNet-50</strong><span>Architecture</span></div>
            <div className="stat-divider"></div>
            <div className="stat"><strong>&lt;3s</strong><span>Inference</span></div>
          </div>
        </div>
        <div className="hero-scroll-hint" onClick={scrollToUpload}>
          <span>Upload Your Image</span>
          <div className="scroll-arrow">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 5v14M5 12l7 7 7-7"/></svg>
          </div>
        </div>
      </section>

      {/* ── UPLOAD / PREDICT ── */}
      <section id="upload" ref={uploadSectionRef} className="upload-section-wrapper reveal">
        <div className="section-container">
          <div className="section-label">AI Identification</div>
          <h2 className="section-title">Upload & Identify</h2>
          <p className="section-subtitle">Drop a clear photo of a cattle or buffalo and let the model do the rest.</p>

          <div className="upload-card">
            {/* Drop Zone */}
            <div
              className={`drop-zone ${dragOver ? 'drag-over' : ''} ${preview ? 'has-preview' : ''}`}
              onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
              onDragLeave={() => setDragOver(false)}
              onDrop={handleDrop}
              onClick={() => !preview && fileInputRef.current?.click()}
            >
              {!preview ? (
                <div className="drop-zone-inner">
                  <div className="drop-icon">
                    <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
                      <path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/>
                      <polyline points="17 8 12 3 7 8"/>
                      <line x1="12" y1="3" x2="12" y2="15"/>
                    </svg>
                  </div>
                  <p className="drop-title">{dragOver ? 'Release to upload' : 'Drag & drop your image'}</p>
                  <p className="drop-or">— or —</p>
                  <button className="btn-browse" type="button" onClick={(e) => { e.stopPropagation(); fileInputRef.current?.click(); }}>
                    Browse Files
                  </button>
                  <p className="drop-hint">JPG · PNG · BMP · Max 50 MB</p>
                </div>
              ) : (
                <div className="preview-wrapper">
                  <img src={preview} alt="Preview" className="preview-img" />
                  <div className="preview-overlay">
                    <button className="btn-change" onClick={(e) => { e.stopPropagation(); handleClear(); }}>
                      <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M3 6h18M8 6V4h8v2M19 6l-1 14H6L5 6"/></svg>
                      Remove
                    </button>
                  </div>
                  <div className="preview-filename">{selectedFile?.name}</div>
                </div>
              )}
            </div>

            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              onChange={handleInputChange}
              style={{ display: 'none' }}
            />

            {/* Action Buttons */}
            <div className="upload-actions">
              <button
                className={`btn-predict ${loading ? 'loading' : ''}`}
                onClick={handlePredict}
                disabled={!selectedFile || loading}
              >
                {loading ? (
                  <>
                    <span className="spinner"></span>
                    Analyzing…
                  </>
                ) : (
                  <>
                    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
                    Identify Breed
                  </>
                )}
              </button>
              {(selectedFile || predictions) && (
                <button className="btn-clear" onClick={handleClear}>
                  Clear
                </button>
              )}
            </div>

            {/* Error */}
            {error && (
              <div className="error-banner">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/></svg>
                {error}
              </div>
            )}

            {/* Results */}
            {predictions && (
              <div className="results-wrapper">
                <div className="results-header">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="22 12 18 12 15 21 9 3 6 12 2 12"/></svg>
                  Analysis Results
                </div>

                {/* Top Match */}
                <div className="top-match-card">
                  <div className="match-left">
                    <div className="match-trophy">🏆</div>
                    <div>
                      <div className="match-label">Top Match</div>
                      <div className="match-breed">{predictions.top_match}</div>
                      {predictions.predictions[0] && (
                        <div className="match-meta">
                          <span className="tag tag-type">{predictions.predictions[0].type}</span>
                          <span className="tag tag-origin">{predictions.predictions[0].origin}</span>
                        </div>
                      )}
                    </div>
                  </div>
                  <div className="match-right">
                    <div className="conf-circle" style={{ '--conf': predictions.confidence, '--conf-color': getConfidenceColor(predictions.confidence) }}>
                      <svg viewBox="0 0 36 36" className="conf-svg">
                        <path className="conf-bg" d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"/>
                        <path className="conf-fill" strokeDasharray={`${predictions.confidence}, 100`} d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831"/>
                      </svg>
                      <div className="conf-text">
                        <strong>{predictions.confidence}%</strong>
                        <span>confidence</span>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Top 3 */}
                <div className="predictions-list">
                  <div className="predictions-list-title">All Predictions</div>
                  {predictions.predictions.map((pred, i) => (
                    <div key={i} className={`pred-row ${i === 0 ? 'pred-top' : ''}`}>
                      <div className="pred-rank">#{i + 1}</div>
                      <div className="pred-info">
                        <div className="pred-name">{pred.breed}</div>
                        <div className="pred-tags">
                          <span className="tag tag-sm">{pred.type}</span>
                          <span className="tag tag-sm tag-muted">{pred.origin}</span>
                        </div>
                      </div>
                      <div className="pred-bar-wrap">
                        <div className="pred-bar">
                          <div className="pred-bar-fill" style={{ width: `${pred.confidence}%`, background: getConfidenceColor(pred.confidence) }}></div>
                        </div>
                        <span className="pred-pct">{pred.confidence}%</span>
                      </div>
                    </div>
                  ))}
                </div>

                <button className="btn-try-again" onClick={handleClear}>
                  Try Another Image
                </button>
              </div>
            )}
          </div>
        </div>
      </section>

      {/* ── FEATURES ── */}
      <section id="features" className="features-section reveal">
        <div className="section-container">
          <div className="section-label">Why BreedAI</div>
          <h2 className="section-title">Built for Precision & Speed</h2>
          <p className="section-subtitle">Everything you need to identify cattle and buffalo breeds with confidence.</p>
          <div className="features-grid">
            {[
              { icon: '🧠', title: 'Deep Learning Core', desc: 'Powered by a fine-tuned ResNet-50 convolutional neural network trained on thousands of livestock images for best-in-class accuracy.' },
              { icon: '⚡', title: 'Under 3 Seconds', desc: 'Optimized inference pipeline delivers breed predictions in under 3 seconds, even on CPU-only deployments.' },
              { icon: '📊', title: 'Confidence Scoring', desc: 'Each prediction comes with a calibrated confidence score and top-3 alternatives so you always have full context.' },
              { icon: '🌍', title: 'Global Breed Coverage', desc: 'Covers indigenous Indian, Zebu, Taurine, and hybrid breeds from over 20 countries and agricultural zones.' },
            ].map((f, i) => (
              <div className="feature-card" key={i}>
                <div className="feature-icon">{f.icon}</div>
                <h3>{f.title}</h3>
                <p>{f.desc}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── HOW IT WORKS ── */}
      <section id="how-it-works" className="hiw-section reveal">
        <div className="section-container">
          <div className="section-label">Process</div>
          <h2 className="section-title">How It Works</h2>
          <p className="section-subtitle">Three simple steps from photo to identification.</p>
          <div className="hiw-steps">
            {[
              { step: '01', icon: '📸', title: 'Upload Image', desc: 'Select or drag-and-drop a clear photo of the cattle or buffalo you want to identify. JPG, PNG, and BMP formats are supported.' },
              { step: '02', icon: '🤖', title: 'AI Processing', desc: 'Our ResNet-50 model extracts visual features — coat color, body structure, horn shape — and compares them against learned breed profiles.' },
              { step: '03', icon: '✅', title: 'Get Results', desc: 'Receive the top matched breed with a confidence score, origin information, and the next two best alternatives instantly.' },
            ].map((s, i) => (
              <div className="hiw-card" key={i}>
                <div className="hiw-step-num">{s.step}</div>
                <div className="hiw-icon">{s.icon}</div>
                <h3>{s.title}</h3>
                <p>{s.desc}</p>
                {i < 2 && <div className="hiw-connector"></div>}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ── ABOUT ── */}
      <section id="about" className="about-section reveal">
        <div className="section-container about-grid">
          <div className="about-text">
            <div className="section-label">About the Project</div>
            <h2 className="section-title left">AI-Powered Livestock Intelligence</h2>
            <p>BreedAI is a deep learning application designed to support farmers, veterinarians, researchers, and agri-tech platforms in accurately identifying cattle and buffalo breeds from photographs.</p>
            <p>The model was trained on a curated dataset covering indigenous and exotic breeds, using transfer learning on <strong>ResNet-50</strong> — a 50-layer residual network architecture proven for fine-grained visual recognition tasks.</p>
            <div className="about-pills">
              <span className="pill">🏗 ResNet-50</span>
              <span className="pill">🔬 Transfer Learning</span>
              <span className="pill">📦 PyTorch</span>
              <span className="pill">🌾 Agricultural AI</span>
              <span className="pill">⚡ FastAPI Backend</span>
            </div>
          </div>
          <div className="about-visual">
            <div className="about-card glass">
              <div className="about-card-row">
                <div className="about-card-stat">
                  <span className="stat-num">50+</span>
                  <span className="stat-lbl">Breeds Covered</span>
                </div>
                <div className="about-card-stat">
                  <span className="stat-num">50L</span>
                  <span className="stat-lbl">ResNet Layers</span>
                </div>
              </div>
              <div className="model-arch">
                {['Input Image', 'Conv Layers', 'Residual Blocks', 'Global Pool', 'Softmax Output'].map((l, i) => (
                  <div key={i} className="arch-step">
                    <div className="arch-dot"></div>
                    <span>{l}</span>
                    {i < 4 && <div className="arch-line"></div>}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* ── CONTACT ── */}
      <section id="contact" className="contact-section reveal">
        <div className="section-container">
          <div className="section-label">Get in Touch</div>
          <h2 className="section-title">Contact</h2>
          <p className="section-subtitle">Interested in the project, want to collaborate, or just have questions?</p>
          <div className="contact-cards">
            {[
              { icon: '✉️', label: 'Email', value: 'your@email.com', href: 'mailto:your@email.com' },
              { icon: '🐙', label: 'GitHub', value: 'github.com/yourprofile', href: 'https://github.com/yourprofile' },
              { icon: '💼', label: 'LinkedIn', value: 'linkedin.com/in/yourprofile', href: 'https://linkedin.com/in/yourprofile' },
            ].map((c, i) => (
              <a className="contact-card glass" href={c.href} target="_blank" rel="noreferrer" key={i}>
                <div className="contact-card-icon">{c.icon}</div>
                <div className="contact-card-label">{c.label}</div>
                <div className="contact-card-value">{c.value}</div>
              </a>
            ))}
          </div>
        </div>
      </section>

      {/* ── FOOTER ── */}
      <footer className="footer">
        <div className="footer-inner">
          <div className="footer-brand">
            <span className="logo-icon">🐄</span>
            <span className="logo-text">BreedAI</span>
          </div>
          <p className="footer-tagline">AI-Powered Cattle & Buffalo Breed Identification</p>
          <p className="footer-tech">Built with ResNet-50 · PyTorch · FastAPI · React</p>
          <p className="footer-copy">© {new Date().getFullYear()} BreedAI. All rights reserved.</p>
        </div>
      </footer>

    </div>
  );
}

export default App;
